    ?contribution a orkgc:C121001 ;
                  orkgp:HAS_EVALUATION ?evaluation .
    ?evaluation orkgp:P181050 ?validationProcedure .
    FILTER NOT EXISTS {
      ?contribution orkgp:P181031 ?annotationProcess2 .
      ?annotationProcess2 orkgp:P181036 ?annotationScheme2 .
    }
    BIND("validation_procedure_only" AS ?coverageType)
  }
