PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?year ?paperCount
WHERE {
  {
    SELECT ?year (COUNT(DISTINCT ?paper) AS ?paperCount)
    WHERE {
      ?paper orkgp:P31 ?contribution ;
             orkgp:P29 ?year .
      ?contribution a orkgc:C121001 ;
                    orkgp:P181011 ?dataset .
      ?dataset orkgp:P181028 ?datasetLocation .
      ?datasetLocation orkgp:P1003 ?datasetUrl .
    }
    GROUP BY ?year
  }
  {
    SELECT (MIN(?cnt) AS ?minCount)
    WHERE {
      {
        SELECT ?year2 (COUNT(DISTINCT ?paper2) AS ?cnt)
        WHERE {
          ?paper2 orkgp:P31 ?contribution2 ;
                  orkgp:P29 ?year2 .
          ?contribution2 a orkgc:C121001 ;
                         orkgp:P181011 ?dataset2 .
          ?dataset2 orkgp:P181028 ?datasetLocation2 .
          ?datasetLocation2 orkgp:P1003 ?datasetUrl2 .
        }
        GROUP BY ?year2
      }
    }
  }
  FILTER(?paperCount = ?minCount)
}
ORDER BY ?year
